oxy_webhelp_navlinks = {"ms_entra_id_recover-d30753e49710":{"topics":[{"title":"Non-recovery of soft-deleted objects by <span class=\"ph\">RSC<\/span>","shortdesc":"<p class=\"shortdesc\"><span class=\"ph\">RSC<\/span> does not recover higher-privileged, soft-deleted Microsoft Entra         ID user or group objects. Instead, <span class=\"ph\">RSC<\/span> creates new objects, leaving the         soft-deleted ones in the Microsoft Recycle Bin.<\/p>","href":"saas\/ms_entra_id_non_recov_soft_del_obj_rsc.html","attributes":{"data-id":"ms_entra_id_non_recov_soft_del_obj_rsc"},"menu":{"hasChildren":false},"tocID":"ms_entra_id_non_recov_soft_del_obj_rsc-d30753e49723","topics":[]},{"title":"Microsoft Entra ID object and relationship recovery","shortdesc":"<p class=\"shortdesc\"><span class=\"ph\">RSC<\/span> recovers Microsoft Entra ID objects and object relationships,         including users, groups, roles, enterprise apps, and app registrations.<\/p>","href":"saas\/ms_entra_id_obj_relationship_recovery.html","attributes":{"data-id":"ms_entra_id_obj_relationship_recovery"},"menu":{"hasChildren":false},"tocID":"ms_entra_id_obj_relationship_recovery-d30753e49741","next":"ms_entra_id_obj_relationship_recovery-d30753e49741"},{"title":"Microsoft Entra ID Conditional Access recovery","shortdesc":"<p class=\"shortdesc\">For Microsoft Entra ID directories that support Conditional Access, <span class=\"ph\">RSC<\/span> can protect Microsoft Entra ID Conditional Access objects and relationships.<\/p>","href":"saas\/ms_entra_id_conditional_access_recovery.html","attributes":{"data-id":"ms_entra_id_conditional_access_recovery"},"menu":{"hasChildren":false},"tocID":"ms_entra_id_conditional_access_recovery-d30753e49872","next":"ms_entra_id_conditional_access_recovery-d30753e49872"},{"title":"Microsoft Entra ID object recovery across snapshots","shortdesc":"<p class=\"shortdesc\">With <span class=\"ph\">RSC<\/span>, you can search Microsoft Entra ID user, groups, and roles         objects for recovery across different snapshots. This functionality enables recovery of         objects and relationships from a specific date and time.<\/p>","href":"saas\/ms_entra_id_obj_recov_across_snapshots.html","attributes":{"data-id":"ms_entra_id_obj_recov_across_snapshots"},"menu":{"hasChildren":false},"tocID":"ms_entra_id_obj_recov_across_snapshots-d30753e49914","next":"ms_entra_id_obj_recov_across_snapshots-d30753e49914"},{"title":"Microsoft Entra ID user object attribute recovery","shortdesc":"<p class=\"shortdesc\">Attribute recovery for a Microsoft Entra ID user object selectively restores specific         attributes that were maliciously or accidentally altered without performing a full object         restore. You can compare user object attributes from a snapshot against live data and         recover only the changed attributes.<\/p>","href":"saas\/ms_entra_id_user_obj_attr_recov.html","attributes":{"data-id":"ms_entra_id_user_obj_attr_recov"},"menu":{"hasChildren":false},"tocID":"ms_entra_id_user_obj_attr_recov-d30753e49961","next":"ms_entra_id_user_obj_attr_recov-d30753e49961"},{"title":"Recovery in a hybrid identity environment","shortdesc":"<p class=\"shortdesc\">In a hybrid Microsoft Entra ID and Active Directory environment on <span class=\"ph\">RSC<\/span>, you can view Active Directory group and user assignments synced from the Active         Directory domain. You can additionally recover relationships for synced Active Directory         user and group objects and protect the Active Direct domain.<\/p>","href":"saas\/ms_entra_id_recovery_hybrid_env.html","attributes":{"data-id":"ms_entra_id_recovery_hybrid_env"},"menu":{"hasChildren":false},"tocID":"ms_entra_id_recovery_hybrid_env-d30753e49994","next":"ms_entra_id_recovery_hybrid_env-d30753e49994"},{"title":"Microsoft Entra ID cross-tenant recovery","shortdesc":"<p class=\"shortdesc\">Microsoft Entra ID cross-tenant recovery restores directory data from a source tenant         to a separate, distinct target tenant to ensure business continuity during catastrophic         events.<\/p>","href":"saas\/ms_entra_id_ctr.html","attributes":{"data-id":"ms_entra_id_ctr"},"menu":{"hasChildren":false},"tocID":"ms_entra_id_ctr-d30753e50044","next":"ms_entra_id_ctr-d30753e50044"},{"title":"Microsoft Entra ID full tenant recovery","shortdesc":"<p class=\"shortdesc\">Using Microsoft Entra ID full tenant recovery, administrators can restore all objects         and relationships in a tenant from a previous state. You can specify objects to exclude from         recovery.<\/p>","href":"saas\/ms_entra_id_full_domain_recov.html","attributes":{"data-id":"ms_entra_id_full_domain_recov"},"menu":{"hasChildren":false},"tocID":"ms_entra_id_full_domain_recov-d30753e50113","next":"ms_entra_id_full_domain_recov-d30753e50113"},{"title":"Microsoft Entra ID device protection","shortdesc":"<p class=\"shortdesc\"><span class=\"ph\">RSC<\/span> protects Microsoft Entra ID device data by securing critical         recovery data against ransomware and accidental data loss.<\/p>","href":"saas\/ms_entra_id_devices_protection.html","attributes":{"data-id":"ms_entra_id_devices_protection"},"menu":{"hasChildren":false},"tocID":"ms_entra_id_devices_protection-d30753e50135","next":"ms_entra_id_devices_protection-d30753e50135"},{"title":"Microsoft Intune device protection","shortdesc":"<p class=\"shortdesc\"><span class=\"ph\">RSC<\/span> protects Microsoft Intune device compliance policies , helping         you maintain a resilient identity and endpoint posture.<\/p>","href":"saas\/ms_entra_id_protect_microsoft_intune.html","attributes":{"data-id":"ms_entra_id_protect_microsoft_intune"},"menu":{"hasChildren":false},"tocID":"ms_entra_id_protect_microsoft_intune-d30753e50194","next":"ms_entra_id_protect_microsoft_intune-d30753e50194"},{"title":"Microsoft Entra ID Identity Governance protection","shortdesc":"<p class=\"shortdesc\"><span class=\"ph\">Rubrik Security Cloud<\/span> protects Microsoft Entra ID Identity Governance objects so         you can recover privileged access policies, entitlement configurations, and access review         definitions alongside identity and endpoint data.<\/p>","href":"saas\/ms_entra_id_protect_idgov.html","attributes":{"data-id":"ms_entra_id_protect_idgov"},"menu":{"hasChildren":false},"tocID":"ms_entra_id_protect_idgov-d30753e50259","next":"ms_entra_id_protect_idgov-d30753e50259"}]}};